opencat.script:
// ── sequential corner entrance ────────────────────────────
ctx.fromTo('video-tl', {opacity:0, x:-80, y:-80, scale:0.85}, {opacity:1, x:0, y:0, scale:1, duration:28, ease:'spring.gentle'});
ctx.fromTo('video-tr', {opacity:0, x:80, y:-80, scale:0.85}, {opacity:1, x:0, y:0, scale:1, duration:28, delay:18, ease:'spring.gentle'});
ctx.fromTo('video-bl', {opacity:0, x:-80, y:80, scale:0.85}, {opacity:1, x:0, y:0, scale:1, duration:28, delay:36, ease:'spring.gentle'});
ctx.fromTo('video-br', {opacity:0, x:80, y:80, scale:0.85}, {opacity:1, x:0, y:0, scale:1, duration:28, delay:54, ease:'spring.gentle'});
